#include <bits/stdc++.h>
using namespace std;
int n;
int dp[32];
int b, c, i, j, k;
int ans;
int main () {
	cin >> n;
	for (int a = 1; a <= n; a++) {
		cin >> b;
		k = 1;
		for (c = 0; c <= 30; c++) {
			if((1 << c) & b) {
				k = max (dp[c] + 1, k);
			}
		}
		for (c = 0; c <= 30; c++) {
			if ((1 << c) & b) {
				dp[c] = k;
			}
		}
		ans = max (ans, k);
	}
	cout << ans;
	return 0;
}
